    'setup',
    'analyze-source',
    'brief-skill',
    'create-skill',
    'quick-skill',
    'create-stack-skill',
    'verify-stack',
    'refine-architecture',
    'update-skill',
    'audit-skill',
    'test-skill',
    'export-skill',
    'rename-skill',
    'drop-skill',
  ];

  for (const workflowName of workflowNames) {
