9	/**
10	 * Derive the expected shortcut from a kebab-case trigger.
11	 * - Single word: first letter (e.g., "help" → "H")
12	 * - Multi-word: first letter of first two words (e.g., "tech-spec" → "TS")
13	 * @param {string} kebabTrigger The kebab-case trigger name.
14	 * @returns {string} The expected uppercase shortcut.
15	 */
16	function deriveShortcutFromKebab(kebabTrigger) {
17	  const words = kebabTrigger.split('-');
18	  if (words.length === 1) {
